import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import ImageZoomModal from './components/ImageZoomModal';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as ch12 } from './hooks/data_ch12';
import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';

import { Trash2, BookOpen, Stethoscope, HeartPulse, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    if (!Object.values(AppMode).includes(savedMode as AppMode)) {
        return AppMode.FLASHCARDS;
    }
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // CENTRALIZED MISTAKE SYSTEM
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  const handleToggleMistake = (id: string, shouldAdd: boolean) => {
    setMistakesVault(prev => {
        if (shouldAdd) {
            return prev.includes(id) ? prev : [...prev, id];
        } else {
            return prev.filter(m => m !== id);
        }
    });
  };

  const handleClearMistakes = () => {
      setMistakesVault([]);
  };

  // --- ULTIMATE DATA ENGINE & INTEGRITY SYSTEM ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const rawSources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    const clean = (str: string | undefined) => str ? str.trim().replace(/\s+/g, ' ') : '';

    const globalAnswerPool: string[] = [];
    const categoryAnswerPools: Record<string, string[]> = {};

    rawSources.forEach(q => {
        const cat = q.category || 'General';
        if (!categoryAnswerPools[cat]) categoryAnswerPools[cat] = [];

        const cleanAnswer = clean(q.answerText);
        if (cleanAnswer && cleanAnswer.length < 100 && !cleanAnswer.toLowerCase().includes('all of the above') && !cleanAnswer.toLowerCase().includes('none of the above')) {
            categoryAnswerPools[cat].push(cleanAnswer);
            globalAnswerPool.push(cleanAnswer);
        }
    });

    rawSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            const cleanQ = {
                ...q,
                questionText: clean(q.questionText),
                answerText: clean(q.answerText),
                explanation: clean(q.explanation),
                options: (q.options || []).map(clean).filter(Boolean)
            };

            let finalOptions = [...cleanQ.options];
            const answerNorm = cleanQ.answerText.toLowerCase();

            if (finalOptions.length < 2) {
                const cat = q.category || 'General';
                let pool = categoryAnswerPools[cat] || [];

                if (pool.length < 10) pool = [...pool, ...globalAnswerPool];

                const validDistractors = pool.filter(a => a.toLowerCase() !== answerNorm);
                const uniqueDistractors = Array.from(new Set(validDistractors));

                const randomDistractors = uniqueDistractors
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [cleanQ.answerText, ...randomDistractors];

                while (finalOptions.length < 4) {
                    const fallbacks = ["None of the above", "All of the above", "Structure not visible", "Not applicable"];
                    for (const fb of fallbacks) {
                        if (!finalOptions.includes(fb) && finalOptions.length < 4) {
                            finalOptions.push(fb);
                        }
                    }
                    if (finalOptions.length < 4) break;
                }

                finalOptions.sort(() => 0.5 - Math.random());
            }

            if (!finalOptions.includes(cleanQ.answerText)) {
                if (finalOptions.length >= 4) {
                    finalOptions.pop(); 
                }
                finalOptions.push(cleanQ.answerText);
                finalOptions.sort(() => 0.5 - Math.random());
            }

            finalOptions = Array.from(new Set(finalOptions));

            uniqueQuestions.push({ ...cleanQ, options: finalOptions });
            seenIds.add(cleanQ.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         <div className="absolute inset-0 bg-white"></div>
         <div className="absolute top-0 left-0 right-0 h-[50vh] md:h-[60vh] bg-slate-50 rounded-b-[3rem] md:rounded-b-[4rem] z-0"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-8 md:space-y-10 animate-fade-in">
            <div className="w-24 h-24 md:w-28 md:h-28 bg-white rounded-3xl shadow-xl shadow-slate-200 flex items-center justify-center relative cursor-pointer hover:scale-105 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-gradient-to-br from-rose-50 to-slate-50 rounded-3xl opacity-50"></div>
                <HeartPulse size={48} className="text-rose-600 relative z-10 md:w-14 md:h-14" strokeWidth={1.5} />
            </div>

            <div className="space-y-3">
               <span className="inline-block px-4 py-1.5 rounded-full bg-amber-50 text-amber-600 text-[11px] font-black uppercase tracking-[0.25em] border border-amber-200 shadow-sm">
                  Occupational Therapy
               </span>
               <h1 className="text-3xl md:text-5xl font-black text-slate-900 tracking-tight leading-tight font-display">
                  Anatomy <span className="text-amber-500">OT</span>
               </h1>
            </div>

            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-xl hover:bg-amber-500 hover:shadow-amber-200 transition-all transform active:scale-95 flex items-center justify-center gap-3"
                >
                     <span>Start Session</span>
                     <ChevronRight size={16} />
                </button>

                <div className="flex justify-center items-center gap-6 md:gap-8 text-slate-300">
                    <div className="flex flex-col items-center gap-1.5">
                        <BookOpen size={18} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{allQuestions.length} Items</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1.5">
                        <Stethoscope size={18} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Medical</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden bg-slate-50/50">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area - Optimized for various screen sizes (Measurements fixed) */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-0 md:pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full md:rounded-[2.5rem] overflow-hidden shadow-none md:shadow-2xl md:border border-white/60 bg-white md:bg-white/80 backdrop-blur-3xl relative z-10 transition-all duration-700 flex flex-col ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Flashcards 
                    data={allQuestions} 
                    onImageClick={setZoomedImage} 
                    mistakes={mistakesVault}
                    onToggleMistake={handleToggleMistake}
                    onClearMistakes={handleClearMistakes}
                />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <InteractiveAtlas 
                    data={allQuestions} 
                    onImageClick={setZoomedImage} 
                    mistakes={mistakesVault}
                />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                  onImageClick={setZoomedImage}
                  mistakes={mistakesVault}
                  onAddMistake={(id) => handleToggleMistake(id, true)}
                  onRemoveMistake={(id) => handleToggleMistake(id, false)}
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in flex-1">
                <QuestionList 
                  data={allQuestions}
                  onImageClick={setZoomedImage}
                  mistakes={mistakesVault}
                  onToggleMistake={handleToggleMistake}
                  onClearMistakes={handleClearMistakes}
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />

      <ImageZoomModal 
        isOpen={!!zoomedImage} 
        imageUrl={zoomedImage || ''} 
        onClose={() => setZoomedImage(null)} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, Info, BookOpen, AlertCircle, 
  BarChart3, ArrowLeft, Filter, Save, Flag, ListChecks, HelpCircle, Activity,
  ImageIcon
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams) {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Error Vault is empty or no mistakes match the selected filters! Great job.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  const updateVault = (questionId: string, isCorrect: boolean) => {
      if (!isCorrect) {
          onAddMistake?.(questionId);
      } else if (mode === 'vault') {
          onRemoveMistake?.(questionId);
      }
  };

  const handleFinish = () => {
    cancel();
    questions.forEach(q => {
        if (q.userAnswer) {
            const isCorrect = q.userAnswer === q.correctOption;
            updateVault(q.id, isCorrect);
        }
    });
    setView('results');
  };

  const handleOptionSelect = (option: string) => {
      if (mode === 'study' || mode === 'vault') {
          if (!questions[currentQIndex].userAnswer) {
             const isCorrect = option === questions[currentQIndex].correctOption;
             updateVault(questions[currentQIndex].id, isCorrect);
          }
      }

      setQuestions(prev => { 
          const c = [...prev]; 
          if ((mode === 'study' || mode === 'vault') && c[currentQIndex].userAnswer) return c;
          c[currentQIndex].userAnswer = option; 
          return c; 
      });
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // --- VIEW: CONFIGURATION ---
  if (view === 'config') {
    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50">
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-amber-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy & Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-amber-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="p-6 md:p-8 space-y-6 overflow-y-auto custom-scrollbar">
                {/* Responsive Grid for Mode Buttons */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Vault</h3>
                            {mistakes.length > 0 && <span className="bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Remediation</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className="p-4 rounded-2xl border border-slate-200 bg-slate-50 hover:bg-white hover:border-rose-200 transition-all flex items-center justify-between group"
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500"><BookOpen size={16}/></div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Source</span>
                                <span className="font-bold text-xs text-slate-700 truncate">
                                    {selectedCategories.length === 0 ? 'All Chapters' : `${selectedCategories.length} Selected`}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className="text-slate-400 group-hover:translate-x-1 transition-transform shrink-0" />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 space-y-3">
                         <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                         </div>
                         <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                         />
                    </div>
                </div>

                <button 
                    onClick={() => setOnlyDiagrams(!onlyDiagrams)}
                    className={`w-full p-4 rounded-2xl border transition-all flex items-center justify-between group ${onlyDiagrams ? 'bg-indigo-50 border-indigo-200' : 'bg-slate-50 border-slate-200 hover:border-indigo-200'}`}
                >
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg border transition-colors ${onlyDiagrams ? 'bg-indigo-100 text-indigo-600 border-indigo-200' : 'bg-white border-slate-200 text-slate-400'}`}>
                            <ImageIcon size={16} />
                        </div>
                        <div className="flex flex-col text-left">
                            <span className={`text-[10px] font-black uppercase tracking-wider ${onlyDiagrams ? 'text-indigo-600' : 'text-slate-400'}`}>Visual Mode</span>
                            <span className={`font-bold text-xs ${onlyDiagrams ? 'text-indigo-900' : 'text-slate-700'}`}>Diagrams Only</span>
                        </div>
                    </div>
                    <div className={`w-10 h-6 rounded-full p-1 transition-colors ${onlyDiagrams ? 'bg-indigo-500' : 'bg-slate-200'}`}>
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform ${onlyDiagrams ? 'translate-x-4' : 'translate-x-0'}`}></div>
                    </div>
                </button>

                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-amber-500 transition-all shadow-xl hover:shadow-amber-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    Start Exam <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => setSelectedCategories([])}
            mainOptions={[]}
            title="Select Exam Chapters"
          />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isStudy = mode === 'study' || mode === 'vault'; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    return (
      <div className="h-full flex flex-col bg-white">
        <header className="h-14 md:h-16 glass border-b border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-lg md:rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div>
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none hidden md:block">
                        {isExam ? 'Assessment' : 'Study'}
                    </h1>
                    <p className="text-xs font-bold text-slate-900 truncate max-w-[120px] md:max-w-none">Anatomy OT</p>
                </div>
            </div>
            <div className="flex items-center gap-2 md:gap-3">
                {isExam && (
                    <div className="px-3 py-1.5 md:px-4 md:py-2 bg-rose-50 text-rose-600 rounded-lg md:rounded-xl font-mono font-bold text-xs md:text-sm border border-rose-100 flex items-center gap-2">
                        <Clock size={14} />
                        {formatTime(timeLeft)}
                    </div>
                )}

                <button 
                    onClick={(e) => toggleFlag(currentQIndex, e)}
                    className={`p-2 rounded-lg md:rounded-xl border transition-all ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                    <Flag size={16} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                </button>

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-50 rounded-lg md:rounded-xl text-slate-400 border border-slate-100"><LayoutGrid size={16} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-6 md:space-y-8 pb-20">
                <div className="space-y-4 md:space-y-6">
                    <div className="flex flex-wrap gap-2">
                        <span className="px-2 py-1 bg-slate-100 text-[9px] md:text-[10px] font-black uppercase text-slate-500 rounded-md border border-slate-200">{currentQ.data.category.split(':')[0]}</span>
                        {currentQ.isFlagged && <div className="flex items-center gap-1 text-[9px] font-bold text-amber-600 bg-amber-50 px-2 py-1 rounded border border-amber-100"><Flag size={10} fill="currentColor"/> FLAGGED</div>}
                    </div>

                    <h2 className="text-lg md:text-2xl font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div className="rounded-2xl border border-slate-100 bg-slate-50 p-2 overflow-hidden cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                            <img src={cleanImageUrl(currentQ.data.questionImage)} className="w-full max-h-[300px] object-contain rounded-xl" alt="Diagram" />
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;

                            let containerClass = "border-slate-200 hover:bg-slate-50";
                            let iconClass = "bg-slate-100 text-slate-500";
                            let iconContent = <span className="text-xs">{String.fromCharCode(65 + i)}</span>;

                            if (isExam) {
                                if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50 ring-1 ring-slate-900 shadow-md";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            } else {
                                if (showFeedback) {
                                    const isCorrect = opt === currentQ.correctOption;
                                    const isWrong = isSelected && !isCorrect;

                                    if (isCorrect) {
                                        containerClass = "border-emerald-500 bg-emerald-50/50";
                                        iconClass = "bg-emerald-500 text-white";
                                        iconContent = <Check size={14} />;
                                    } else if (isWrong) {
                                        containerClass = "border-rose-500 bg-rose-50/50";
                                        iconClass = "bg-rose-500 text-white";
                                        iconContent = <X size={14} />;
                                    } else {
                                        containerClass = "opacity-50 border-slate-100";
                                    }
                                } else if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            }

                            return (
                                <button 
                                    key={i} 
                                    onClick={() => handleOptionSelect(opt)} 
                                    className={`w-full p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 text-left group min-h-[60px] ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-medium text-sm md:text-base text-slate-800" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {showFeedback && (
                    <div className="p-5 md:p-6 bg-slate-900 text-white rounded-2xl space-y-3 animate-in slide-in-from-bottom-2 duration-300 shadow-xl">
                        <div className="flex items-center gap-2 text-rose-400">
                            <Info size={18} />
                            <h4 className="font-black uppercase text-[10px] tracking-[0.2em]">Rationale</h4>
                        </div>
                        <p className="text-sm text-slate-300 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification based on standard anatomical terminology." }} />
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 bg-white/95 backdrop-blur z-30 fixed bottom-0 left-0 right-0 md:relative">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-4 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>

            {currentQIndex === questions.length - 1 ? (
                <button 
                    onClick={goToSummary} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-amber-500 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Submit Exam <ListChecks size={16} />
                </button>
            ) : (
                <button 
                    onClick={() => setCurrentQIndex(c => c + 1)} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-amber-500 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Next <ChevronRight size={16} />
