import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, Info, BookOpen, AlertCircle, 
  BarChart3, ArrowLeft, Flag, ListChecks, Activity,
  ImageIcon
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Professional Notification State
  const [notification, setNotification] = useState<{show: boolean, type: 'add' | 'remove'}>({ show: false, type: 'add' });

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams) {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Smart Review is empty! Great job mastering the content.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  // --- IMMEDIATE MISTAKE SYSTEM LOGIC ---
  const handleOptionSelect = (option: string) => {
      const currentQ = questions[currentQIndex];

      // If already answered in Study/Vault mode, ignore click
      if ((mode === 'study' || mode === 'vault') && currentQ.userAnswer) return;

      const isCorrect = option === currentQ.correctOption;

      // 1. Update Local State
      setQuestions(prev => { 
          const c = [...prev]; 
          c[currentQIndex].userAnswer = option; 
          return c; 
      });

      // 2. Immediate Smart Review Update
      if (!isCorrect) {
          // If wrong, add to mistakes immediately
          onAddMistake?.(currentQ.id);

          // Show "Added" Notification
          setNotification({ show: true, type: 'add' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      } 
      else if (isCorrect && mode === 'vault') {
          // If correct AND we are in Review Mode, remove it
          onRemoveMistake?.(currentQ.id);

          // Show "Removed/Mastered" Notification
          setNotification({ show: true, type: 'remove' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      }
  };

  const handleFinish = () => {
    cancel();

    // AUTOMATICALLY ADD UNANSWERED OR WRONG QUESTIONS TO MISTAKES
    questions.forEach(q => {
        const isWrongOrSkipped = q.userAnswer !== q.correctOption;
        if (isWrongOrSkipped) {
            onAddMistake?.(q.id);
        }
    });

    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // --- VIEW: CONFIGURATION ---
  if (view === 'config') {
    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50 pb-24 md:pb-4">
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[80vh] md:max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-amber-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy And Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-amber-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="p-6 md:p-8 space-y-6 overflow-y-auto custom-scrollbar pb-12">
                {/* Responsive Grid for Mode Buttons */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Smart Review</h3>
                            {mistakes.length > 0 && <span className="bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Fix Mistakes</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className="p-4 rounded-2xl border border-slate-200 bg-slate-50 hover:bg-white hover:border-rose-200 transition-all flex items-center justify-between group"
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500"><BookOpen size={16}/></div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Source</span>
                                <span className="font-bold text-xs text-slate-700 truncate">
                                    {selectedCategories.length === 0 ? 'All Chapters' : `${selectedCategories.length} Selected`}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className="text-slate-400 group-hover:translate-x-1 transition-transform shrink-0" />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 space-y-3">
                         <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                         </div>
                         <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                         />
                    </div>
                </div>

                <div className="pt-2">
                    <button 
                        onClick={startSession}
                        disabled={currentPoolSize === 0}
                        className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-amber-500 transition-all shadow-xl hover:shadow-amber-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                    >
                        Start Exam <ChevronRight size={16} />
                    </button>
                </div>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => setSelectedCategories([])}
            mainOptions={[]}
            title="Select Exam Chapters"
          />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isStudy = mode === 'study' || mode === 'vault'; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    return (
      <div className="h-full flex flex-col bg-white relative">

        {/* --- PROFESSIONAL NOTIFICATION --- */}
        {notification.show && (
            <div className="absolute top-20 left-0 right-0 flex justify-center z-50 pointer-events-none animate-in fade-in slide-in-from-top-4">
                <div className={`px-6 py-3 rounded-full shadow-2xl border-2 flex items-center gap-3 font-bold text-xs uppercase tracking-widest ${
                    notification.type === 'add' 
                    ? 'bg-amber-500 text-white border-white' 
                    : 'bg-emerald-500 text-white border-white'
                }`}>
                    {notification.type === 'add' ? (
                        <>
                            <AlertTriangle size={16} className="fill-current text-white" />
                            <span>Added to Smart Review</span>
                        </>
                    ) : (
                        <>
                            <CheckCircle2 size={16} className="fill-current text-white" />
                            <span>Mastered & Removed</span>
                        </>
                    )}
                </div>
            </div>
        )}

        <header className="h-14 md:h-16 glass border-b border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-lg md:rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
