                  <button onClick={restartQuiz} className="w-full py-3.5 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  RotateCcw, Info, Search
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

interface FlashcardsProps {
  data: Question[];
  onImageClick?: (url: string) => void;
  mistakes?: string[]; // Prop from App
  onToggleMistake?: (id: string, shouldAdd: boolean) => void; // Prop from App
  onClearMistakes?: () => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ 
    data, 
    onImageClick, 
    mistakes = [], 
    onToggleMistake, 
    onClearMistakes 
}) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [touchStart, setTouchStart] = useState<{ x: number; y: number } | null>(null);
  const [touchEnd, setTouchEnd] = useState<{ x: number; y: number } | null>(null);
  const minSwipeDistance = 50;

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakes.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakes, isShuffled]);

  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;
      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onToggleMistake?.(id, false);
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        onClearMistakes?.();
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    if (currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distanceX = touchStart.x - touchEnd.x;
    const distanceY = touchStart.y - touchEnd.y;
    if (Math.abs(distanceX) > Math.abs(distanceY)) {
      if (distanceX > minSwipeDistance) handleNext();
      else if (distanceX < -minSwipeDistance) handlePrev();
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    if (len < 30) return 'text-xl md:text-5xl';
    if (len < 80) return 'text-lg md:text-4xl';
    if (len < 150) return 'text-base md:text-3xl';
    if (len < 300) return 'text-sm md:text-2xl';
    return 'text-xs md:text-xl';
  };

  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Study',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => { setShowImagesOnly(!showImagesOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-4 md:px-6 py-2 md:py-6 shrink-0 gap-3 overflow-x-auto no-scrollbar">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center shrink-0 ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>

           {mistakes.length > 0 && (
                <button 
                    onClick={() => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) setCurrentIndex(0); }}
                    className={`flex items-center gap-2 px-3 py-1 md:py-2 md:px-4 rounded-xl border transition-all shrink-0 ${showMistakesOnly ? 'bg-amber-100 border-amber-300 text-amber-800 shadow-sm' : 'bg-white border-slate-200 text-slate-500 hover:border-amber-200 hover:text-amber-600'}`}
                >
                    <AlertTriangle size={16} className={showMistakesOnly ? "fill-amber-500 text-amber-600" : ""} />
                    <div className="flex flex-col items-start text-[10px] uppercase font-black tracking-wider leading-none">
                        <span>Smart Review</span>
                        <span className="opacity-60 text-[9px] mt-0.5">{mistakes.length} Items</span>
                    </div>
                </button>
           )}
        </div>

        <div className="flex items-center gap-2">
           <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1 mr-2 hidden sm:flex">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
           </span>

           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-2 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full max-h-[700px] cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-6 md:p-12 flex flex-col items-center text-center group">
               <div className="w-full flex justify-between items-start mb-2 md:mb-6 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-1 md:py-2 space-y-4 md:space-y-6 overflow-y-auto custom-scrollbar">
                 {frontContent.image && (
                   <div 
                     className="flex-1 min-h-0 w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-slate-50/50 border border-slate-100 relative group/img cursor-zoom-in"
                     onClick={(e) => { e.stopPropagation(); onImageClick?.(frontContent.image!); }}
                   >
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                     <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Search size={14} />
                     </div>
                   </div>
                 )}

                 <h2 
                    className={`font-bold leading-tight text-slate-800 break-words w-full font-display ${getTextSizeClass(frontDisplayText)}`} 
                    dangerouslySetInnerHTML={{ __html: frontDisplayText }} 
                 />

                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-5 bg-rose-50/50 rounded-xl border border-rose-100 text-left mt-2 md:mt-4 animate-in fade-in slide-in-from-bottom-2 relative shrink-0">
                     <div className="flex items-center gap-2 mb-1 md:mb-2 text-rose-600/70">
                        <Info className="w-3 h-3 md:w-3.5 md:h-3.5" />
                        <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-xs md:text-sm font-medium text-slate-700 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, frontDisplayText, '-front')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-slate-900 text-white rounded-full hover:bg-rose-600 shadow-xl shadow-slate-200 hover:shadow-rose-200 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-front') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-white rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>

            {/* BACK FACE */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] shadow-premium border border-slate-800 p-6 md:p-12 flex flex-col items-center text-center group">
               <div className="w-full flex justify-between items-start mb-2 md:mb-6 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-600">
                     {backContent.label}
                   </span>
                   {mistakes.includes(currentCard.id) && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-amber-500/20 text-amber-400 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-emerald-500/20 hover:text-emerald-400 transition-colors border border-amber-500/30 shadow-lg"
                        >
                            <CheckCircle2 size={12} /> Mastered
                        </button>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-1 md:py-2 space-y-4 md:space-y-6 overflow-y-auto custom-scrollbar">
                 {backContent.image && (
                   <div 
                     className="flex-1 min-h-0 w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-white/5 border border-white/10 relative group/img cursor-zoom-in"
                     onClick={(e) => { e.stopPropagation(); onImageClick?.(backContent.image!); }}
                   >
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                     <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Search size={14} />
                     </div>
                   </div>
                 )}

                 <p 
                    className={`font-bold leading-relaxed text-emerald-400 break-words w-full font-display ${getTextSizeClass(backDisplayText)}`} 
                    dangerouslySetInnerHTML={{ __html: backDisplayText }} 
                 />

                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-6 bg-white/5 rounded-2xl border border-white/10 text-left mt-2 md:mt-4 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <div className="flex items-center gap-2 mb-1 md:mb-2 text-slate-400">
                        <Info className="w-3 h-3 md:w-3.5 md:h-3.5" />
                        <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-xs md:text-sm font-medium text-slate-300 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, backDisplayText, '-back')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white text-slate-900 rounded-full hover:bg-emerald-400 hover:text-white shadow-xl shadow-black/20 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-back') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-current rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation - Bottom */}
      <div className="px-6 pb-6 pt-2 flex justify-center gap-4 md:gap-6 items-center shrink-0">
        <button onClick={handlePrev} disabled={currentIndex === 0} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowLeft className="w-5 h-5 md:w-6 md:h-6" />
        </button>

        <button onClick={() => setIsFlipped(!isFlipped)} className="h-12 md:h-14 px-8 md:px-12 rounded-2xl bg-rose-600 flex items-center gap-3 text-white transition-all shadow-lg font-black uppercase text-[10px] md:text-xs tracking-[0.2em] group">
            <RotateCcw className={`w-4 h-4 md:w-[18px] md:h-[18px] transition-transform duration-500 ${isFlipped ? '-rotate-180' : 'rotate-0'}`} />
            Flip Card
        </button>

        <button onClick={handleNext} disabled={currentIndex === activeData.length - 1} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowRight className="w-5 h-5 md:w-6 md:h-6" />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakes.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

export default Flashcards;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check, Volume2, VolumeX
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import { useSpeech } from '../hooks/useSpeech';
import { cleanImageUrl } from '../utils';

// Text Cleaning Helper
const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuestionListProps {
  data: Question[];
  onImageClick?: (url: string) => void;
  mistakes?: string[]; // Prop from App
  onToggleMistake?: (id: string, shouldAdd: boolean) => void; // Prop from App
  onClearMistakes?: () => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ 
    data, 
    onImageClick, 
    mistakes = [], 
    onToggleMistake, 
    onClearMistakes 
}) => {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState(''); 
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the Smart Review list?")) {
      onToggleMistake?.(id, false);
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire Smart Review history. Are you sure?")) {
        onClearMistakes?.();
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const handleSpeak = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
        cancel();
    } else {
        speak(text, id);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakes.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakes]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Smart Review',
        subLabel: `${mistakes.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-4 md:pt-6">
      {/* Search Header */}
      <div className={`rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-12 mb-6 md:mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-4 md:space-y-6">
          <div className="space-y-2">
            <h2 className="text-2xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Review" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Focus List" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder={showMistakesOnly ? "Search review items..." : "Search anatomy terms, chapters or definitions..."}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
            />
            <Search className="absolute left-4 md:left-5 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-slate-500 transition-colors" size={20} />
          </div>

          <div className="flex flex-wrap gap-2 md:gap-3 items-center">
            {/* Filter Trigger Button */}
            <button 
              onClick={() => setIsFilterOpen(true)}
              className="flex items-center gap-2 px-4 md:px-6 py-2.5 md:py-3 bg-white text-slate-900 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest shadow-lg hover:bg-slate-100 transition-all"
            >
              <Filter size={14} /> Filters
              {(selectedCategories.length > 0 || showMistakesOnly || showWrittenOnly) && (
                 <span className="bg-slate-900 text-white px-2 py-0.5 rounded-md">Active</span>
              )}
            </button>

            {showMistakesOnly && mistakes.length > 0 && (
                <button 
                    onClick={clearAllMistakes}
                    className="flex items-center gap-2 px-4 py-3 rounded-xl bg-black/20 text-white hover:bg-white hover:text-amber-600 transition-all text-[10px] font-black uppercase"
                >
                    <Trash2 size={14} /> Clear Review
                </button>
            )}

            <div className="flex-1"></div>
            <button 
                onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors text-white"
                title="Sort A-Z"
            >
                <ArrowUpDown size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid - content-visibility: auto speeds up rendering */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakes.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden" onClick={() => onImageClick?.(q.questionImage!)}>
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg cursor-zoom-in" loading="lazy" />
                </div>
              )}
              <div className="p-6 md:p-8 flex-1">
                <div className="flex items-center justify-between mb-3 md:mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 max-w-[70%] truncate">{q.category}</span>
                  <div className="flex items-center gap-2">
                    {/* Audio Button */}
                    <button 
                        onClick={(e) => handleSpeak(e, `${formatQuestionText(q.questionText)} ... Answer: ${q.answerText}`, q.id)}
                        className={`w-8 h-8 flex items-center justify-center rounded-lg transition-colors ${isSpeaking && speakingId === q.id ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-600'}`}
                        title="Listen"
                    >
                        {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                    </button>

                    {mistakes.includes(q.id) && (
                        <div className="flex items-center gap-2">
                            <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Review</span>
                            <button 
                                onClick={(e) => removeMistake(q.id, e)}
                                className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                                title="Resolve this item"
                            >
                                <Check size={12} />
                            </button>
                        </div>
                    )}
                  </div>
                </div>
                <h3 className="text-lg md:text-xl font-black text-slate-800 leading-tight mb-3" dangerouslySetInnerHTML={{ __html: highlightText(formatQuestionText(q.questionText), debouncedSearch) }} />
                <div className="relative pl-4 md:pl-6 border-l-4 border-slate-200">
                  <p className="text-sm md:text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "Review list is empty. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakes.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Library Filters"
      />
    </div>
  );
};

